 30→
 31→    const workspace = await fetchJson<{ workspaceId: string; conversationId: string }>(`${baseUrl}/api/workspaces`, {
 32→      method: "POST",
 33→      headers: { "Content-Type": "application/json" },
 34→      body: JSON.stringify({
 35→        name: `Pipeline Smoke ${Date.now()}`,
 36→        ownerDisplayName: "Marcus",
 37→      }),
 38→    });
 39→
 40→    const message = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
 41→      method: "POST",
 42→      headers: { "Content-Type": "application/json" },
 43→      body: JSON.stringify({
 44→        clientMessageId: randomUUID(),
 45→        workspaceId: workspace.workspaceId,
 46→        conversationId: workspace.conversationId,
 47→        text: "I decided to use TypeScript over Rust for backend implementation.",
 48→      }),
 49→    });
 50→
 51→    const events = await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 5_000);
 52→    const extractionEvent = events.find((event) => event.type === "extraction");
 53→    const assistantEvent = events.find((event) => event.type === "assistant_message");
 54→
 55→    expect(extractionEvent).toBeDefined();
 56→    expect(assistantEvent).toBeDefined();
 57→
 58→    if (!extractionEvent || extractionEvent.type !== "extraction") {
 59→      throw new Error("Expected extraction event in SSE stream");
 60→    }
 61→    expect(extractionEvent.entities.some((entity) => entity.kind === "decision")).toBe(true);
 62→
 63→    const userMessageRecord = new RecordId("message", message.userMessageId);
 64→    const [decisionRows] = await surreal
 65→      .query<[Array<{ id: RecordId<"decision", string>; summary: string; embedding?: number[] }>]>(
 66→        "SELECT id, summary, embedding FROM decision WHERE source_message = $sourceMessage;",
 67→        { sourceMessage: userMessageRecord },
 68→      )
 69→      .collect<[Array<{ id: RecordId<"decision", string>; summary: string; embedding?: number[] }>]>();
 70→
 71→    expect(decisionRows.length).toBeGreaterThan(0);
 72→    const decision = decisionRows[0];
 73→    if (!decision) {
 74→      throw new Error("Decision record was not persisted");
 75→    }
 76→
 77→    expect(decision.summary.length).toBeGreaterThan(0);
 78→    expect(Array.isArray(decision.embedding)).toBe(true);
 79→    expect((decision.embedding ?? []).length).toBeGreaterThan(0);
 80→
 81→    const [edgeRows] = await surreal
 82→      .query<[
 83→        Array<{
 84→          id: RecordId<"extraction_relation", string>;
 85→          evidence?: string;
 86→          evidence_source?: RecordId<"message", string>;
 87→          resolved_from?: RecordId<"message", string>;
 88→        }>,
 89→      ]>(
 90→        "SELECT id, evidence, evidence_source, resolved_from FROM extraction_relation WHERE `in` = $sourceMessage AND out = $decision LIMIT 1;",
 91→        { sourceMessage: userMessageRecord, decision: decision.id },
 92→      )
 93→      .collect<[
 94→        Array<{
 95→          id: RecordId<"extraction_relation", string>;
 96→          evidence?: string;
 97→          evidence_source?: RecordId<"message", string>;
 98→          resolved_from?: RecordId<"message", string>;
 99→        }>,
100→      ]>();
101→
102→    expect(edgeRows.length).toBe(1);
103→    const edge = edgeRows[0];
104→    if (!edge) {
105→      throw new Error("Expected extraction_relation edge");
106→    }
107→    expect(typeof edge.evidence).toBe("string");
108→
109→    if (!edge.evidence) {
110→      throw new Error("Expected evidence text on extraction_relation edge");
111→    }
112→
113→    const normalizedInput = normalizeText("I decided to use TypeScript over Rust for backend implementation.");
114→    const normalizedEvidence = normalizeText(edge.evidence);
115→    expect(normalizedInput.includes(normalizedEvidence)).toBe(true);
116→    expect(edge.evidence_source?.id as string | undefined).toBe(message.userMessageId);
117→    expect(edge.resolved_from).toBeUndefined();
118→
119→    const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
120→    const [personRows] = await surreal
121→      .query<[Array<{ id: RecordId<"person", string> }>]>(
122→        "SELECT id FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
123→        { workspace: workspaceRecord },
124→      )
125→      .collect<[Array<{ id: RecordId<"person", string> }>]>();
126→
127→    expect(personRows.length).toBe(1);
128→
129→    if (!assistantEvent || assistantEvent.type !== "assistant_message") {
130→      throw new Error("Expected assistant_message event in SSE stream");
131→    }
132→    expect(assistantEvent.text.includes("```component")).toBe(true);
133→  }, 30_000);
134→});
