import { describe, expect, it } from "bun:test";
import { randomUUID } from "node:crypto";
import { RecordId, type Surreal } from "surrealdb";
import { fetchJson, setupSmokeSuite } from "./smoke-test-kit";

type BranchConversationResponse = {
  conversationId: string;
  parentConversationId: string;
  branchPointMessageId: string;
};

type ConversationResponse = {
  conversationId: string;
  messages: Array<{
    id: string;
    role: string;
    text: string;
    createdAt: string;
    inherited?: boolean;
  }>;
};

const getRuntime = setupSmokeSuite("branch-inheritance");

async function createConversation(surreal: Surreal, workspaceId: string): Promise<string> {
  const convId = randomUUID();
  const now = new Date();
  await surreal.query("CREATE $record CONTENT $content;", {
    record: new RecordId("conversation", convId),
    content: {
      createdAt: now,
      updatedAt: now,
      workspace: new RecordId("workspace", workspaceId),
      title: "Test conversation",
      title_source: "message",
    },
  });
  return convId;
}

async function insertMessage(
  surreal: Surreal,
  conversationId: string,
  role: "user" | "assistant",
  text: string,
  createdAt: Date,
): Promise<string> {
  const msgId = randomUUID();
  await surreal.query("CREATE $record CONTENT $content;", {
    record: new RecordId("message", msgId),
    content: {
      conversation: new RecordId("conversation", conversationId),
      role,
      text,
      createdAt,
    },
  });
  return msgId;
}

async function branchFrom(
  baseUrl: string,
  workspaceId: string,
  parentConversationId: string,
  messageId: string,
): Promise<BranchConversationResponse> {
  return fetchJson<BranchConversationResponse>(
    `${baseUrl}/api/workspaces/${workspaceId}/conversations/${parentConversationId}/branch`,
    {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ messageId }),
    },
  );
}

async function loadConversation(
  baseUrl: string,
  workspaceId: string,
  conversationId: string,
): Promise<ConversationResponse> {
  return fetchJson<ConversationResponse>(
    `${baseUrl}/api/workspaces/${workspaceId}/conversations/${conversationId}`,
  );
}

describe("branch inheritance smoke", () => {
  it("branch conversation includes inherited messages from parent", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Create workspace (needed for API validation)
    const workspace = await fetchJson<{ workspaceId: string; conversationId: string }>(
      `${baseUrl}/api/workspaces`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: `Branch Smoke ${Date.now()}`,
          ownerDisplayName: "Marcus",
        }),
      },
    );

    // Create a clean conversation (no onboarding messages)
    const rootConvId = await createConversation(surreal, workspace.workspaceId);
    const now = Date.now();
    const ts = (offset: number) => new Date(now + offset);

    // Seed root conversation with 5 messages (3 user + 2 assistant pairs, plus 1 extra)
    const msg1 = await insertMessage(surreal, rootConvId, "user", "Root user msg 1", ts(1000));
    await insertMessage(surreal, rootConvId, "assistant", "Root assistant reply 1", ts(2000));
    const msg3 = await insertMessage(surreal, rootConvId, "user", "Root user msg 2", ts(3000));
    await insertMessage(surreal, rootConvId, "assistant", "Root assistant reply 2", ts(4000));
    await insertMessage(surreal, rootConvId, "user", "Root user msg 3 (after branch point)", ts(5000));

    // Branch from msg3 — should inherit msg1, reply1, msg3, reply2
    const branch = await branchFrom(baseUrl, workspace.workspaceId, rootConvId, msg3);

    expect(branch.conversationId).toBeDefined();
    expect(branch.parentConversationId).toBe(rootConvId);
    expect(branch.branchPointMessageId).toBe(msg3);

    // Insert messages into the branch
    await insertMessage(surreal, branch.conversationId, "user", "Branch user msg", ts(10000));
    await insertMessage(surreal, branch.conversationId, "assistant", "Branch assistant reply", ts(11000));

    // Load branch conversation via API — exercises loadMessagesWithInheritance
    const conv = await loadConversation(baseUrl, workspace.workspaceId, branch.conversationId);

    expect(conv.conversationId).toBe(branch.conversationId);

    const inherited = conv.messages.filter((m) => m.inherited === true);
    const own = conv.messages.filter((m) => !m.inherited);

    // Inherited: msg1, reply1, msg3, reply2 (branch point + its assistant response)
    const inheritedTexts = inherited.map((m) => m.text);
    expect(inheritedTexts).toContain("Root user msg 1");
    expect(inheritedTexts).toContain("Root assistant reply 1");
    expect(inheritedTexts).toContain("Root user msg 2");
    expect(inheritedTexts).toContain("Root assistant reply 2");

    // msg5 is AFTER the branch point — must NOT be inherited
    expect(inheritedTexts).not.toContain("Root user msg 3 (after branch point)");

    // Own messages from the branch
    const ownTexts = own.map((m) => m.text);
    expect(ownTexts).toContain("Branch user msg");
    expect(ownTexts).toContain("Branch assistant reply");

    // Messages should be chronologically ordered
    for (let i = 1; i < conv.messages.length; i++) {
      expect(new Date(conv.messages[i].createdAt).getTime()).toBeGreaterThanOrEqual(
        new Date(conv.messages[i - 1].createdAt).getTime(),
      );
    }
  }, 30_000);

  it("multi-level branching inherits from all ancestors", async () => {
    const { baseUrl, surreal } = getRuntime();

    const workspace = await fetchJson<{ workspaceId: string; conversationId: string }>(
      `${baseUrl}/api/workspaces`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: `MultiLevel Branch ${Date.now()}`,
          ownerDisplayName: "Marcus",
        }),
      },
    );

    const rootConvId = await createConversation(surreal, workspace.workspaceId);
    const now = Date.now();
    const ts = (offset: number) => new Date(now + offset);

    // ── Root conversation: 2 user/assistant pairs ──
    const rootMsg1 = await insertMessage(surreal, rootConvId, "user", "Root msg 1", ts(1000));
    await insertMessage(surreal, rootConvId, "assistant", "Root reply 1", ts(2000));
    await insertMessage(surreal, rootConvId, "user", "Root msg 2", ts(3000));
    await insertMessage(surreal, rootConvId, "assistant", "Root reply 2", ts(4000));

    // ── Branch A from root at rootMsg1 ──
    const branchA = await branchFrom(baseUrl, workspace.workspaceId, rootConvId, rootMsg1);

    // Branch A inherits root msg1 + reply1 (branch point + assistant response)
    // Add 2 pairs of messages to Branch A
    const branchAMsg1 = await insertMessage(surreal, branchA.conversationId, "user", "Branch A msg 1", ts(10000));
    await insertMessage(surreal, branchA.conversationId, "assistant", "Branch A reply 1", ts(11000));
    await insertMessage(surreal, branchA.conversationId, "user", "Branch A msg 2", ts(12000));
    await insertMessage(surreal, branchA.conversationId, "assistant", "Branch A reply 2", ts(13000));

    // ── Branch B from Branch A at branchAMsg1 ──
    const branchB = await branchFrom(baseUrl, workspace.workspaceId, branchA.conversationId, branchAMsg1);

    // Add messages to Branch B
    await insertMessage(surreal, branchB.conversationId, "user", "Branch B msg 1", ts(20000));
    await insertMessage(surreal, branchB.conversationId, "assistant", "Branch B reply 1", ts(21000));

    // ── Verify Branch A ──
    const convA = await loadConversation(baseUrl, workspace.workspaceId, branchA.conversationId);
    const inheritedA = convA.messages.filter((m) => m.inherited === true).map((m) => m.text);
    const ownA = convA.messages.filter((m) => !m.inherited).map((m) => m.text);

    // Branch A inherits root msg1 + reply1
    expect(inheritedA).toContain("Root msg 1");
    expect(inheritedA).toContain("Root reply 1");
    // Must NOT inherit root messages after branch point
    expect(inheritedA).not.toContain("Root msg 2");
    expect(inheritedA).not.toContain("Root reply 2");
    // Branch A's own messages
    expect(ownA).toContain("Branch A msg 1");
    expect(ownA).toContain("Branch A reply 1");
    expect(ownA).toContain("Branch A msg 2");
    expect(ownA).toContain("Branch A reply 2");

    // ── Verify Branch B (multi-level) ──
    const convB = await loadConversation(baseUrl, workspace.workspaceId, branchB.conversationId);
    const inheritedB = convB.messages.filter((m) => m.inherited === true).map((m) => m.text);
    const ownB = convB.messages.filter((m) => !m.inherited).map((m) => m.text);

    // From root: msg1 + reply1 (inherited via Branch A's chain to root)
    expect(inheritedB).toContain("Root msg 1");
    expect(inheritedB).toContain("Root reply 1");
    // Root messages after Branch A's branch point are excluded
    expect(inheritedB).not.toContain("Root msg 2");
    expect(inheritedB).not.toContain("Root reply 2");

    // From Branch A: msg1 + reply1 (up to Branch B's branch point)
    expect(inheritedB).toContain("Branch A msg 1");
    expect(inheritedB).toContain("Branch A reply 1");
    // Branch A messages after Branch B's branch point are excluded
    expect(inheritedB).not.toContain("Branch A msg 2");
    expect(inheritedB).not.toContain("Branch A reply 2");

    // Branch B's own messages
    expect(ownB).toContain("Branch B msg 1");
    expect(ownB).toContain("Branch B reply 1");

    // Verify chronological ordering across the full chain
    for (let i = 1; i < convB.messages.length; i++) {
      expect(new Date(convB.messages[i].createdAt).getTime()).toBeGreaterThanOrEqual(
        new Date(convB.messages[i - 1].createdAt).getTime(),
      );
    }

    // Verify chain depth: Branch B has 2 links (root → A → B)
    const [chainRows] = await surreal
      .query<[Array<{ out: RecordId }>]>(
        "SELECT out FROM branched_from WHERE `in` = $conv LIMIT 1;",
        { conv: new RecordId("conversation", branchB.conversationId) },
      )
      .collect<[Array<{ out: RecordId }>]>();

    expect(chainRows.length).toBe(1);
    expect(chainRows[0].out.id as string).toBe(branchA.conversationId);

    const [parentChainRows] = await surreal
      .query<[Array<{ out: RecordId }>]>(
        "SELECT out FROM branched_from WHERE `in` = $conv LIMIT 1;",
        { conv: new RecordId("conversation", branchA.conversationId) },
      )
      .collect<[Array<{ out: RecordId }>]>();

    expect(parentChainRows.length).toBe(1);
    expect(parentChainRows[0].out.id as string).toBe(rootConvId);
  }, 30_000);
});
